-- Migration: Set up mind_coach_personas and mind_coach_pathway_phases tables

-- Drop the old table
DROP TABLE IF EXISTS public.mind_coach_prompts;

-- Create Personas Table
CREATE TABLE IF NOT EXISTS public.mind_coach_personas (
    id TEXT PRIMARY KEY,
    description TEXT NOT NULL,
    image_url TEXT NOT NULL,
    base_prompt TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

ALTER TABLE public.mind_coach_personas ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read personas" ON public.mind_coach_personas FOR SELECT USING (true);

-- Create Pathway Phases Table
CREATE TABLE IF NOT EXISTS public.mind_coach_pathway_phases (
    id TEXT PRIMARY KEY,
    pathway_id TEXT NOT NULL,
    pathway_name TEXT NOT NULL,
    pathway_description TEXT NOT NULL,
    phase_number INT NOT NULL,
    phase_name TEXT NOT NULL,
    phase_description TEXT NOT NULL,
    dynamic_prompt TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

ALTER TABLE public.mind_coach_pathway_phases ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read pathway phases" ON public.mind_coach_pathway_phases FOR SELECT USING (true);

-- Insert Personas
ON CONFLICT (id) DO UPDATE SET base_prompt = EXCLUDED.base_prompt;

-- Insert Pathway Phases
ON CONFLICT (id) DO UPDATE SET dynamic_prompt = EXCLUDED.dynamic_prompt;
